/// Package license definition.
class Package {
  /// Package name
  final String name;

  /// Description
  final String description;

  /// Authors
  final List<String> authors;

  /// Whether the license is in markdown format or not (plain text).
  final bool isMarkdown;

  /// Whether the package is included in the SDK or not.
  final bool isSdk;

  /// Direct dependencies
  final List<PackageRef> dependencies;

  /// Direct devDependencies
  final List<PackageRef> devDependencies;

  /// Website URL
  final String? homepage;

  /// Repository URL
  final String? repository;

  /// Version
  final String? version;

  /// License
  final String? license;

  /// The [SPDX](https://spdx.org/licenses/) license identifiers, if detected.
  final List<String> spdxIdentifiers;

  const Package({
    required this.name,
    required this.description,
    required this.authors,
    required this.isMarkdown,
    required this.isSdk,
    required this.dependencies,
    required this.devDependencies,
    this.homepage,
    this.repository,
    this.version,
    this.license,
    this.spdxIdentifiers = const [],
  });
}

class PackageRef {
  final String name;

  const PackageRef(this.name);

  Package resolve() => allDependencies.firstWhere((d) => d.name == name);
}

